// Creates mop_kb collection + 9 keyword payload indexes if absent.
// Idempotent: GET first, PUT only on 404.

const http = require('http');
const QDRANT_HOST = 'qdrant';
const QDRANT_PORT = 6333;
const QDRANT_KEY = (() => { try { const e = require('fs').readFileSync('/proc/1/environ','utf8').split(String.fromCharCode(0)).find(x => x.startsWith('QDRANT_API_KEY=')); return e ? e.slice(15) : ''; } catch(_) { return ''; } })();
const COLLECTION  = 'mop_kb';

function qdrantReq(method, path, body) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const headers = { 'Content-Type': 'application/json', 'api-key': QDRANT_KEY };
    if (data) headers['Content-Length'] = Buffer.byteLength(data);
    const req = http.request(
      { hostname: QDRANT_HOST, port: QDRANT_PORT, path, method, headers },
      (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => {
          const text = Buffer.concat(chunks).toString();
          try { resolve({ status: res.statusCode, data: JSON.parse(text) }); }
          catch (e) { resolve({ status: res.statusCode, data: text }); }
        });
      }
    );
    req.on('error', reject);
    if (data) req.write(data);
    req.end();
  });
}

const check = await qdrantReq('GET', `/collections/${COLLECTION}`);

if (check.status !== 200) {
  const create = await qdrantReq('PUT', `/collections/${COLLECTION}`, {
    vectors: { size: 768, distance: 'Cosine' },
  });
  if (create.status !== 200) {
    throw new Error('mop_kb creation failed: ' + JSON.stringify(create.data).slice(0, 300));
  }

  // 9 keyword payload indexes (mirror of memory_v1)
  const INDEXES = ['doc_kind', 'repo', 'host_origin', 'source_kind', 'severity', 'category', 'phase', 'topic', 'tags'];
  for (const field of INDEXES) {
    const r = await qdrantReq('PUT', `/collections/${COLLECTION}/index`, {
      field_name: field,
      field_schema: 'keyword',
    });
    if (r.status !== 200) {
      throw new Error(`Index creation failed for ${field}: ${JSON.stringify(r.data).slice(0, 200)}`);
    }
  }
}

// Pass through
return $input.all().map(item => ({ json: item.json, binary: item.binary }));

// For each uploaded PDF:
//   1. Call LiteLLM mop-ingest (Gemini 2.5 Pro multimodal) → structured markdown
//   2. Chunk markdown (header-split + paragraph, 1600 chars, 200 overlap)
//   3. Embed chunks in batches via mop-embed (text-embedding-004, 768 dims)
//   4. Delete old points for same filename+namespace, upsert new batch to mop_kb
// Architecture mirrors memory_v1 (25 payload fields, UUID from SHA256).

const http   = require('http');
const crypto = require('crypto');

const LITELLM_HOST = 'litellm';
const LITELLM_PORT = 4000;
const QDRANT_HOST  = 'qdrant';
const QDRANT_PORT  = 6333;
const COLLECTION   = 'mop_kb';
const LITELLM_KEY = (() => { try { const e = require('fs').readFileSync('/proc/1/environ','utf8').split(String.fromCharCode(0)).find(x => x.startsWith('LITELLM_API_KEY=')); return e ? e.slice(16) : ''; } catch(_) { return ''; } })();
const QDRANT_KEY = (() => { try { const e = require('fs').readFileSync('/proc/1/environ','utf8').split(String.fromCharCode(0)).find(x => x.startsWith('QDRANT_API_KEY=')); return e ? e.slice(15) : ''; } catch(_) { return ''; } })();
const GOTENBERG_HOST = 'gotenberg';
const GOTENBERG_PORT = 3000;

function httpReq(host, port, method, path, body, extraHeaders) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const headers = { 'Content-Type': 'application/json', ...(extraHeaders || {}) };
    if (data) headers['Content-Length'] = Buffer.byteLength(data);
    const req = http.request({ hostname: host, port, path, method, headers }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve({ status: res.statusCode, data: JSON.parse(text) }); }
        catch (e) { resolve({ status: res.statusCode, data: text }); }
      });
    });
    req.on('error', reject);
    if (data) req.write(data);
    req.end();
  });
}

function llm(path, body) {
  return httpReq(LITELLM_HOST, LITELLM_PORT, 'POST', path, body, { Authorization: `Bearer ${LITELLM_KEY}` });
}

function qdrant(method, path, body) {
  return httpReq(QDRANT_HOST, QDRANT_PORT, method, path, body, { 'api-key': QDRANT_KEY });
}

function sha256hex(s) {
  return crypto.createHash('sha256').update(s).digest('hex');
}

function gotenbergConvert(filename, buf, mimeType) {
  return new Promise((resolve, reject) => {
    const boundary = 'GotenbergBoundary' + Date.now();
    const CRLF = '\r\n';
    const header = Buffer.from(
      '--' + boundary + CRLF +
      'Content-Disposition: form-data; name="files"; filename="' + filename + '"' + CRLF +
      'Content-Type: ' + mimeType + CRLF + CRLF
    );
    const footer = Buffer.from(CRLF + '--' + boundary + '--' + CRLF);
    const body = Buffer.concat([header, buf, footer]);
    const headers = {
      'Content-Type': 'multipart/form-data; boundary=' + boundary,
      'Content-Length': body.length,
    };
    const req = http.request(
      { hostname: GOTENBERG_HOST, port: GOTENBERG_PORT, path: '/forms/libreoffice/convert', method: 'POST', headers },
      (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => resolve({ status: res.statusCode, data: Buffer.concat(chunks) }));
      }
    );
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function toUUID(hex) {
  return [hex.slice(0,8), hex.slice(8,12), '4' + hex.slice(13,16), hex.slice(16,20), hex.slice(20,32)].join('-');
}

function chunkMarkdown(text) {
  const MAX = 1600, OVL = 200;
  const sections = text.split(/(?=\n#{1,3} )/);
  const chunks = [];
  for (const sec of sections) {
    if (!sec.trim()) continue;
    if (sec.length <= MAX) { chunks.push(sec.trim()); continue; }
    const paras = sec.split(/\n\n+/);
    let buf = '';
    for (const p of paras) {
      if (!p.trim()) continue;
      const candidate = buf ? buf + '\n\n' + p : p;
      if (candidate.length <= MAX) { buf = candidate; continue; }
      if (buf.trim()) chunks.push(buf.trim());
      if (p.length <= MAX) { buf = p; continue; }
      let s = p;
      while (s.length > MAX) { chunks.push(s.slice(0, MAX)); s = s.slice(MAX - OVL); }
      buf = s;
    }
    if (buf.trim()) chunks.push(buf.trim());
  }
  return chunks.filter(c => c.length >= 20);
}

function sectionHeader(chunk) {
  const m = chunk.match(/^#{1,3} (.+)/m);
  return m ? m[1].trim() : '';
}

// ── main ──────────────────────────────────────────────────────────────────────
const item     = $input.first();
const formData = item.json || {};
const binary   = item.binary || {};

const category   = String(formData.category   || 'sp');
const namespace  = String(formData.namespace  || 'mop').trim() || 'mop';
const language   = String(formData.language   || 'fr');
const sourceKind = String(formData.source_kind || 'reference');
const indexedAt  = new Date().toISOString();
const results    = [];

const MIME_MAP = {
  pdf:  'application/pdf',
  pptx: 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  docx: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  xlsx: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  xls:  'application/vnd.ms-excel',
  xlsm: 'application/vnd.ms-excel.sheet.macroEnabled.12',
  xlsb: 'application/vnd.ms-excel.sheet.binary.macroEnabled.12',
  csv:  'text/csv',
};
const MSG2MD_HOST = 'msg2md';
const MSG2MD_PORT = 3100;

function mimeFromName(n) {
  const ext = (n.match(/\.([^.]+)$/) || [])[1] || '';
  return MIME_MAP[ext.toLowerCase()] || 'application/octet-stream';
}
const files = await Promise.all(
  Object.entries(binary)
    .filter(([, v]) => v && v.data)
    .map(async ([key, v]) => {
      const fn = v.fileName || key;
      const buf = await helpers.getBinaryDataBuffer(0, key);
      return { key, filename: fn, mimeType: v.mimeType || mimeFromName(fn), base64: buf.toString('base64') };
    })
);

if (files.length === 0) throw new Error('Aucun fichier trouvé dans le formulaire');

const INGEST_PROMPTS = {
  pdf:  "Tu es un expert en systèmes télécom (DWDM, SDH, IP/MPLS). Extrais la totalité de ce document technique NOC en markdown structuré. Respecte la hiérarchie: H1 titre, H2 sections, H3 sous-sections. Tableaux en format markdown. Procédures en listes numérotées. Conserve tous les codes alarme, références SP et commandes CLI. Retourne UNIQUEMENT le markdown, sans préambule ni commentaire.",
  pptx: "Tu es un expert en systèmes télécom. Ce fichier est une présentation PowerPoint. Extrais le contenu de chaque diapositive en markdown structuré: H2 pour chaque titre de slide, H3 pour les sous-titres. Transcris tous les textes, tableaux, listes et légendes d'images. Conserve codes alarme, références SP et commandes CLI. Retourne UNIQUEMENT le markdown, sans préambule ni commentaire.",
  docx: "Tu es un expert en systèmes télécom (DWDM, SDH, IP/MPLS). Ce fichier est un document Word. Extrais son contenu en markdown structuré: H1 titre principal, H2 chapitres, H3 sous-sections. Tableaux en format markdown. Procédures en listes numérotées. Conserve tous les codes alarme, références SP et commandes CLI. Retourne UNIQUEMENT le markdown, sans préambule ni commentaire.",
  xlsx: "Tu es un expert en systèmes télécom (DWDM, SDH, IP/MPLS). Ce document est un tableau de base de connaissances NOC converti en PDF. Chaque ligne est un type d'incident ou une procédure. Les colonnes typiques sont : type de perte, réseau, descriptif, impact, cause probable, étapes de résolution, processus de communication, criticité, exemples d'alarmes.\n\nExtrais chaque entrée non-vide en markdown structuré :\n- H2 pour chaque type d'incident/perte\n- Sous chaque H2 : listes des champs renseignés (Cause, Résolution, Criticité, Exemples d'alarmes, etc.)\n- Préserve les codes alarme, noms d'équipements, références opérateurs.\n- Ignore les lignes entièrement vides.\nRetourne UNIQUEMENT le markdown, sans préambule ni commentaire.",
  msg_images: "Tu es un expert en systèmes télécom (DWDM, SDH, IP/MPLS, Ribbon). Ces captures d'écran proviennent d'un échange de support technique NOC. Décris chaque image en markdown structuré :\n- Ce que l'interface affiche (type d'outil : NMS, CLI, alarme, PM counters, etc.)\n- Les éléments techniques visibles : nœuds, ports, valeurs PM, états d'alarmes, commandes CLI et leur output, timestamps\n- Toute valeur numérique ou code d'alarme lisible\n\nFormat : une section H3 par image, titrée \"Capture N\".\nRetourne UNIQUEMENT le markdown, sans préambule ni commentaire.",
};

['xls', 'xlsm', 'xlsb', 'csv'].forEach(e => INGEST_PROMPTS[e] = INGEST_PROMPTS.xlsx);

const EMBED_BATCH  = 50;
const UPSERT_BATCH = 100;

for (const file of files) {
  const fileExt = ((file.filename.match(/\.([^.]+)$/) || [])[1] || 'pdf').toLowerCase();
  const INGEST_PROMPT = INGEST_PROMPTS[fileExt] || INGEST_PROMPTS.pdf;

  // ── .msg: msg2md sidecar → markdown + optional Gemini image descriptions ──
  if (fileExt === 'msg') {
    const rawBuf = Buffer.from(file.base64, 'base64');
    const boundary2 = 'Msg2mdBoundary' + Date.now();
    const CRLF2 = '\r\n';
    const msgHeader = Buffer.from(
      '--' + boundary2 + CRLF2 +
      'Content-Disposition: form-data; name="file"; filename="' + file.filename + '"' + CRLF2 +
      'Content-Type: application/vnd.ms-outlook' + CRLF2 + CRLF2
    );
    const msgFooter = Buffer.from(CRLF2 + '--' + boundary2 + '--' + CRLF2);
    const msgBody = Buffer.concat([msgHeader, rawBuf, msgFooter]);
    const msg2mdResp = await new Promise((resolve, reject) => {
      const req2 = http.request(
        { hostname: MSG2MD_HOST, port: MSG2MD_PORT, path: '/convert', method: 'POST',
          headers: { 'Content-Type': 'multipart/form-data; boundary=' + boundary2, 'Content-Length': msgBody.length } },
        (res2) => {
          const chunks2 = [];
          res2.on('data', c => chunks2.push(c));
          res2.on('end', () => {
            const text2 = Buffer.concat(chunks2).toString();
            try { resolve({ status: res2.statusCode, data: JSON.parse(text2) }); }
            catch (e) { resolve({ status: res2.statusCode, data: text2 }); }
          });
        }
      );
      req2.on('error', reject);
      req2.write(msgBody);
      req2.end();
    });
    if (msg2mdResp.status !== 200) {
      throw new Error(`msg2md conversion failed (${file.filename}): HTTP ${msg2mdResp.status} — ` + JSON.stringify(msg2mdResp.data).slice(0, 200));
    }
    const { markdown: msgMarkdown, images: msgImages } = msg2mdResp.data;
    let fullMarkdown = msgMarkdown;
    if (msgImages && msgImages.length > 0) {
      const imageContent = [
        { type: 'text', text: INGEST_PROMPTS.msg_images },
        ...msgImages.map(img => ({
          type: 'image_url',
          image_url: { url: `data:${img.mimeType};base64,${img.base64}` },
        })),
      ];
      const imgResp = await llm('/v1/chat/completions', {
        model: 'mop-ingest',
        max_tokens: 4096,
        messages: [{ role: 'user', content: imageContent }],
      });
      if (imgResp.status === 200) {
        const imageDescriptions = imgResp.data.choices[0].message.content;
        fullMarkdown = msgMarkdown + '\n\n## Descriptions visuelles\n' + imageDescriptions;
      }
    }
    const titleM2 = fullMarkdown.match(/^#\s+(.+)/m);
    const docTitle2 = titleM2 ? titleM2[1].trim() : file.filename.replace(/\.msg$/i, '');
    const contentHash2 = sha256hex(fullMarkdown);
    const refDocId2 = sha256hex(`${namespace}:${file.filename}:${indexedAt}`);
    const chunks2 = chunkMarkdown(fullMarkdown);
    if (chunks2.length === 0) throw new Error(`Aucun chunk produit pour ${file.filename}`);
    await qdrant('POST', `/collections/${COLLECTION}/points/delete`, {
      filter: { must: [
        { key: 'filename', match: { value: file.filename } },
        { key: 'namespace', match: { value: namespace } },
      ]},
    });
    const allVecs2 = [];
    for (let i = 0; i < chunks2.length; i += EMBED_BATCH) {
      const batch = chunks2.slice(i, i + EMBED_BATCH);
      const embResp = await llm('/v1/embeddings', { model: 'mop-embed', input: batch });
      if (embResp.status !== 200) throw new Error('Embedding échoué (msg): ' + JSON.stringify(embResp.data).slice(0, 300));
      const sorted = [...embResp.data.data].sort((a, b) => a.index - b.index);
      allVecs2.push(...sorted.map(e => e.embedding));
    }
    const points2 = chunks2.map((chunk, idx) => ({
      id: toUUID(sha256hex(`${refDocId2}:${idx}:${chunk.slice(0, 64)}`)),
      vector: allVecs2[idx],
      payload: {
        schema_version: '1.0', embedding_model: 'text-embedding-004', embedding_dim: 768,
        chunking_strategy_version: '1.0', ref_doc_id: refDocId2, repo: '', namespace,
        host_origin: 'sese-ai', source_kind: sourceKind, doc_kind: category, topic: '',
        severity: '', category, phase: '', relative_path: file.filename, filename: file.filename,
        language, tags: [], git_commit_sha: '', content_hash: contentHash2,
        chunk_index: idx, chunk_count: chunks2.length, chunking_kind: 'markdown_paragraph',
        section: sectionHeader(chunk), title: docTitle2, indexed_at: indexedAt, text: chunk,
      },
    }));
    for (let i = 0; i < points2.length; i += UPSERT_BATCH) {
      const r = await qdrant('PUT', `/collections/${COLLECTION}/points`, { points: points2.slice(i, i + UPSERT_BATCH) });
      if (r.status !== 200) throw new Error('Qdrant upsert échoué (msg): ' + JSON.stringify(r.data).slice(0, 300));
    }
    results.push({ filename: file.filename, chunks: chunks2.length, ref_doc_id: refDocId2 });
    continue;
  }
  // ── end .msg branch ─────────────────────────────────────────────────────────

  // 1a. Convert non-PDF (docx, pptx) → PDF via Gotenberg (Gemini only supports PDF)
  let sendFile = file;
  if (['docx', 'doc', 'pptx', 'ppt', 'xlsx', 'xls', 'xlsm', 'xlsb', 'csv'].includes(fileExt)) {
    const rawBuf = Buffer.from(file.base64, 'base64');
    const convResp = await gotenbergConvert(file.filename, rawBuf, file.mimeType);
    if (convResp.status !== 200) {
      throw new Error(`Conversion Gotenberg échouée (${file.filename}): HTTP ${convResp.status} — ` + convResp.data.toString().slice(0, 200));
    }
    sendFile = {
      ...file,
      filename: file.filename.replace(/\.(docx?|pptx?)$/i, '.pdf'),
      mimeType: 'application/pdf',
      base64: convResp.data.toString('base64'),
    };
  }

  // 1b. LLM extraction (Gemini 2.5 Pro multimodal)
  const llmResp = await llm('/v1/chat/completions', {
    model: 'mop-ingest',
    max_tokens: 8192,
    messages: [{ role: 'user', content: [
      { type: 'text', text: INGEST_PROMPT },
      { type: 'image_url', image_url: { url: `data:${sendFile.mimeType};base64,${sendFile.base64}` } },
    ]}],
  });
  if (llmResp.status !== 200) {
    throw new Error(`Extraction LLM échouée (${file.filename}): ` + JSON.stringify(llmResp.data).slice(0, 300));
  }
  const markdown   = llmResp.data.choices[0].message.content;
  const titleM     = markdown.match(/^#\s+(.+)/m);
  const docTitle   = titleM ? titleM[1].trim() : file.filename.replace(/\.(pdf|pptx|docx)$/i, '');
  const contentHash = sha256hex(markdown);
  const refDocId   = sha256hex(`${namespace}:${file.filename}:${indexedAt}`);

  // 2. Chunk
  const chunks = chunkMarkdown(markdown);
  if (chunks.length === 0) throw new Error(`Aucun chunk produit pour ${file.filename}`);

  // 3. Delete old points (same filename + namespace = idempotent re-ingest)
  await qdrant('POST', `/collections/${COLLECTION}/points/delete`, {
    filter: { must: [
      { key: 'filename',  match: { value: file.filename } },
      { key: 'namespace', match: { value: namespace } },
    ]},
  });

  // 4. Embed in batches of 50
  const allVecs = [];
  for (let i = 0; i < chunks.length; i += EMBED_BATCH) {
    const batch = chunks.slice(i, i + EMBED_BATCH);
    const embResp = await llm('/v1/embeddings', { model: 'mop-embed', input: batch });
    if (embResp.status !== 200) {
      throw new Error('Embedding échoué: ' + JSON.stringify(embResp.data).slice(0, 300));
    }
    const sorted = [...embResp.data.data].sort((a, b) => a.index - b.index);
    allVecs.push(...sorted.map(e => e.embedding));
  }

  // 5. Build points (25 payload fields — memory_v1 schema)
  const points = chunks.map((chunk, idx) => ({
    id: toUUID(sha256hex(`${refDocId}:${idx}:${chunk.slice(0, 64)}`)),
    vector: allVecs[idx],
    payload: {
      schema_version:            '1.0',
      embedding_model:           'text-embedding-004',
      embedding_dim:             768,
      chunking_strategy_version: '1.0',
      ref_doc_id:                refDocId,
      repo:                      '',
      namespace,
      host_origin:               'sese-ai',
      source_kind:               sourceKind,
      doc_kind:                  category,
      topic:                     '',
      severity:                  '',
      category,
      phase:                     '',
      relative_path:             file.filename,
      filename:                  file.filename,
      language,
      tags:                      [],
      git_commit_sha:            '',
      content_hash:              contentHash,
      chunk_index:               idx,
      chunk_count:               chunks.length,
      chunking_kind:             'markdown_paragraph',
      section:                   sectionHeader(chunk),
      title:                     docTitle,
      indexed_at:                indexedAt,
      text:                      chunk,
    },
  }));

  // 6. Upsert in batches of 100
  for (let i = 0; i < points.length; i += UPSERT_BATCH) {
    const r = await qdrant('PUT', `/collections/${COLLECTION}/points`, { points: points.slice(i, i + UPSERT_BATCH) });
    if (r.status !== 200) {
      throw new Error('Qdrant upsert échoué: ' + JSON.stringify(r.data).slice(0, 300));
    }
  }

  results.push({ filename: file.filename, chunks: chunks.length, ref_doc_id: refDocId });
}

return [{ json: {
  ok: true,
  files: results,
  total_chunks: results.reduce((s, r) => s + r.chunks, 0),
} }];
